1	import { describe, it, expect } from "vitest";
2	import { run } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge cases: empty / processing fee only ---
6	  it("empty item list yields premium 5 G (processing fee only)", () => {
7	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [] }] });
8	    expect(out).toEqual({ results: [{ premium: 5 }] });
9	  });
10	
11	  // --- Base premiums per main item type ---
12	  it.todo("quote for a single plain sword → premium 105 G (100 base + 5 fee)");
13	  it.todo("quote for a single plain amulet → premium 65 G (60 base + 5 fee)");
14	  it.todo("quote for a single plain staff → premium 85 G (80 base + 5 fee)");
15	  it.todo("quote for a single plain potion → premium 45 G (40 base + 5 fee)");
16	
17	  // --- Components base premium (per-component default) ---
18	  it.todo("quote for 2 runes → 50 G base premium (+5 fee = 55)");
19	
20	  // --- Building block of 3 alike components ---
21	  it.todo("quote for 3 runes → 60 G base premium (block applies) (+5 fee = 65)");
22	  it.todo("quote for 4 runes → 100 G base premium (no block — requires exactly 3) (+5 fee = 105)");
23	  it.todo("quote for 7 runes → 175 G base premium (block of 3 + 4 singles) (+5 fee = 180)");
24	
25	  // --- 'Alike' components clarified by type ---
26	  it.todo("quote for 2 runes + 1 moonstone → 75 G base premium (no block: different types) (+5 fee = 80)");
27	  it.todo("quote for 3 runes + 3 moonstones → 120 G base premium (two separate blocks) (+5 fee = 125)");
28	
29	  // --- Single-modifier surcharges/discounts on a single item ---
30	  it.todo("cursed sword alone (new customer, 1st contract) → 100 base + 50 curse + 10 first-ins + 5 fee = 165 G");
31	  it.todo("high-enchantment sword (enchantment 5) alone (new customer, 1st contract) → 100 + 30 + 10 + 5 = 145 G");
32	  it.todo("sword with enchantment 4 alone (new customer, 1st contract) → no high-ench surcharge → 115 G");
33	
34	  // --- Modifier thresholds ---
35	  it.todo("customer with exactly 2 years gets loyalty discount (plain sword, 1st contract) → 100 - 20 + 10 + 5 = 95 G");
36	  it.todo("cursed sword with exactly enchantment 5 gets both surcharges → 100 + 50 + 30 + 10 + 5 = 195 G");
37	
38	  // --- Multi-item policy & modifier scope ---
39	  it.todo("cursed sword + plain amulet (new customer, 1st contract) → 100+60 base, cursed adds 50 (of sword only), first-ins 10% of policy total → 160 + 50 + 16 + 5 = 231 G");
40	
41	  // --- Follow-up contract discount (15% on each contract after first) ---
42	  it.todo("second quote in scenario: cursed sword + plain amulet, 0 years → first ins still 10%, follow-up 15% off policy total");
43	
44	  // --- Integration examples ---
45	  it.todo("newcomer cursed sword (0 years, no prior): 100 + 50 + 10 + 5 = 165 G");
46	  it.todo("long-standing customer's 2nd contract, cursed enchantment-7 sword (3 years): 100 + 50 + 30 - 20 + 10 - 15 + 5 = 160 G");
47	
48	  // --- Rounding in MHPCO's favor ---
49	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
50	
51	  // --- Claim: basic deductible & standard reimbursement ---
52	  it.todo("steel sword enchantment 3, damage 500 → payout 400 (500 - 100 deductible)");
53	  it.todo("damage to a rune (250 G), damage 200 → payout 100 (200 - 100 deductible)");
54	
55	  // --- Claim: high-enchantment 50% clause ---
56	  it.todo("steel sword enchantment 9, damage 1000 → payout 400 (50% then deductible: 500 - 100)");
57	
58	  // --- Claim: dragon material full reimbursement ---
59	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 (full minus deductible)");
60	
61	  // --- Claim: dragon + high enchantment combined (50% wins) ---
62	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 (high-ench applies first then deductible)");
63	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
64	
65	  // --- Claim: deductible per damage event ---
66	  it.todo("dragon attack damages insured sword 500 and amulet 300 → payout 600 (deductible applies once per damaged item)");
67	
68	  // --- Multiple items of same type ---
69	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; two sword damage entries each get own deductible");
70	  it.todo("claim with more sword damages than swords insured → CLI exits non-zero (claim rejected)");
71	
72	  // --- Cap exhaustion ---
73	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
74	  it.todo("cursed sword cap is 2000 G (based on unmodified insurance value, premium modifiers do not raise cap)");
75	  it.todo("sword + 3 runes block: insurance sum 1750 G (block discount affects premium only, not insurance sum)");
76	  it.todo("sword (cap 2000): claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");
77	
78	  // --- Rounding payout ---
79	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
80	
81	  // --- Error cases ---
82	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with error to stderr");
83	  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero");
84	  it.todo("claim contains damage entry with negative amount → CLI exits non-zero");
85	});
